#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long p,q,r,s; scanf("%lld %lld %lld %lld", &p,&q,&r,&s);
        long long total = p+q+r+s;
        if(p>total-p || q>total-q || r>total-r || s>total-s) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

