#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        p = int(next(it)); q = int(next(it)); r = int(next(it)); s = int(next(it))
        total = p + q + r + s
        if p > total - p or q > total - q or r > total - r or s > total - s:
            out.append("YES")
        else:
            out.append("NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

